models.ts:
/*
id => primary key, snowflake id
*/
interface User {
  id: number;
}

/*
id => primary key, snowflake id
user_id => create an index
updated_at => created at insert time
created_at => created at insert time
*/
interface Chat {
  id: number;
  user_id: number;
  title: string;
  updated_at: string;
  created_at: string;
}

/*
id => primary key, snowflake id
chat => foreign key; create an index
created_at => created at insert time
*/
interface Message {
  id: number;
  chat: Chat;
  content: string;
  role: "user" | "assistant";
  created_at: string;
}

interface GetChatsRequest {
  cursor?: number;
  maxChats?: number;
}

interface CreateMessageRequest {
  chat_id: number;
  content: string;
}

/*
id => primary key, snowflake id
message => foreign key
chat => foreign key
*/
interface UserMessage {
  id: number;
  content: string;
  message: Message;
  chat: Chat;
}
